class Solution:

def is_valid_bst(self, root):
	if not root:
		return True
	min_val = float('-inf')
	max_val = float('inf')
	return self.check_bst(root, min_val, max_val)

def check_bst(self, node, min_val, max_val):
	if node is None:
		return True
	if node.val <= min_val or node.val >= max_val:
		return False
	return self.check_bst(node.left, min_val, node.val) and self.check_bst(node.right, node.val, max_val)

